from typing import Dict
import requests

class UserService:
    def __init__(self, user_repository_url: str):
        self.user_repository_url = user_repository_url

    def create_user(self, user_id: int, name: str, email: str) -> Dict:
        """Create a new user."""
        try:
            response = requests.post(
                f"{self.user_repository_url}/users",
                json={"user_id": user_id, "name": name, "email": email},
            )
            response.raise_for_status()
            return response.json()
        except requests.RequestException as e:
            # Handle the exception
            print(f"Error creating user: {e}")
            return {}

    def get_user(self, user_id: int) -> Dict:
        """Retrieve a user by ID."""
        try:
            response = requests.get(f"{self.user_repository_url}/users/{user_id}")
            response.raise_for_status()
            return response.json()
        except requests.RequestException as e:
            # Handle the exception
            print(f"Error retrieving user: {e}")
            return {}

# Example usage
